mapper.select:
SELECT * FROM SYS_RIGHT WHERE ENABLED_FLAG=1
AND ID=#{id}
AND upper(NAME) like upper('%${name}%')
AND PARENT_ID=#{parentId}
AND upper(STATUS) like upper('%${status}%')
AND upper(URL) like upper('%${url}%')
AND upper(CODE) like upper('%${code}%')
AND SEQ=#{seq}
AND upper(MEMO) like upper('%${memo}%')
AND ENABLED_FLAG=#{enabledFlag}
ORDER BY ID

SELECT * FROM SYS_RIGHT WHERE ENABLED_FLAG=1
AND ID=#{bo.id}
AND upper(NAME) like upper('%${bo.name}%')
AND PARENT_ID=#{bo.parentId}
AND upper(STATUS) like upper('%${bo.status}%')
AND upper(URL) like upper('%${bo.url}%')
AND upper(CODE) like upper('%${bo.code}%')
AND SEQ=#{bo.seq}
AND upper(MEMO) like upper('%${bo.memo}%')
AND ENABLED_FLAG=#{bo.enabledFlag}
ORDER BY ${page.sortFieldName} DESC
